#include "engine/orb/messages/InvokeMethodMessage.h"


ShipDeedAdapter::ShipDeedAdapter(ShipDeed* obj) : DeedAdapter(obj) {
}

void ShipDeedAdapter::invokeMethod(uint32 methid, DistributedMethod* inv) {
	DOBMessage* resp = inv->getInvocationMessage();

	switch (methid) {
	case RPC_INITIALIZETRANSIENTMEMBERS__:
		{
			
			initializeTransientMembers();
			
		}
		break;
	case RPC_SETCONTROLDEVICETEMPLATE__STRING_:
		{
			String templateString; inv->getAsciiParameter(templateString);
			
			setControlDeviceTemplate(templateString);
			
		}
		break;
	case RPC_SETHITPOINTSDAMAGE__FLOAT_:
		{
			float value = inv->getFloatParameter();
			
			setHitPointsDamage(value);
			
		}
		break;
	case RPC_SETMAXHITPOINTS__FLOAT_:
		{
			float value = inv->getFloatParameter();
			
			setMaxHitPoints(value);
			
		}
		break;
	case RPC_SETMASS__FLOAT_:
		{
			float value = inv->getFloatParameter();
			
			setMass(value);
			
		}
		break;
	case RPC_SETCERTIFICATIONREQUIRED__STRING_:
		{
			String cert; inv->getAsciiParameter(cert);
			
			setCertificationRequired(cert);
			
		}
		break;
	case RPC_SETPARKINGLOCATION__STRING_:
		{
			String loc; inv->getAsciiParameter(loc);
			
			setParkingLocation(loc);
			
		}
		break;
	case RPC_SETCREATECOMPONENTS__BOOL_:
		{
			bool val = inv->getBooleanParameter();
			
			setCreateComponents(val);
			
		}
		break;
	case RPC_ADDSKILLREQUIRED__STRING_:
		{
			String skill; inv->getAsciiParameter(skill);
			
			addSkillRequired(skill);
			
		}
		break;
	case RPC_GETCONTROLDEVICETEMPLATE__:
		{
			
			String _m_res = getControlDeviceTemplate();
			resp->insertAscii(_m_res);
		}
		break;
	case RPC_GETHITPOINTSDAMAGE__:
		{
			
			float _m_res = getHitPointsDamage();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETMAXHITPOINTS__:
		{
			
			float _m_res = getMaxHitPoints();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETMASS__:
		{
			
			float _m_res = getMass();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETPARKINGLOCATION__:
		{
			
			String _m_res = getParkingLocation();
			resp->insertAscii(_m_res);
		}
		break;
	case RPC_GETCERTIFICATIONREQUIRED__:
		{
			
			String _m_res = getCertificationRequired();
			resp->insertAscii(_m_res);
		}
		break;
	case RPC_GETTOTALSKILLSREQUIRED__:
		{
			
			int _m_res = getTotalSkillsRequired();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_GETSKILLREQUIRED__INT_:
		{
			int index = inv->getSignedIntParameter();
			
			String _m_res = getSkillRequired(index);
			resp->insertAscii(_m_res);
		}
		break;
	case RPC_SHOULDCREATECOMPONENTS__:
		{
			
			bool _m_res = shouldCreateComponents();
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_GETSHIPTYPE__:
		{
			
			int _m_res = getShipType();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_ISSHIPDEEDOBJECT__:
		{
			
			bool _m_res = isShipDeedObject();
			resp->insertBoolean(_m_res);
		}
		break;
	default:
		DeedAdapter::invokeMethod(methid, inv);
	}
}

